#include <iostream>

int main() {
    int data[] = {4, 8, 15, 16, 23, 42};
    int target = 16;
    for (int i = 0; i < 6; i++) {
        if (data[i] == target) {
            std::cout << "Found " << target << " at index " << i << std::endl;
            break;
        }
    }
    return 0;
}
